@@ -157,7 +157,8 @@ pub fn genExprStmt(self: *NativeCodegen, expr: ast.Node) CodegenError!void {
     // Determine if we should skip semicolon
     // Skip for: block statements, statement-level labeled blocks, wrapped labeled blocks
